import base64, os
data = """"""
content = base64.b64decode(data)
os.makedirs('dashboard', exist_ok=True)
open('dashboard/index.html','wb').write(content)
size = os.path.getsize('dashboard/index.html')
print(f'Written: {size} bytes')
c = open('dashboard/index.html').read()
print(f'Portefeuille: {c.count("Portefeuille")}')
print(f'cDistDiv: {c.count("cDistDiv")}')
